VALUES
  ('locality-6e2f88c7-moex-00226', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於無主物先占之敘述，何者正確？', '["先占乃屬事實行為，故不以具有法律上之完全行為能力為必要", "先占為一法律行為，得經由代理人代理為之", "無主物先占之客體，得為無主之動產或不動產", "所謂無主物，限於自始無主之物，若為原所有人拋棄之物，則不得對其主張先占"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00227', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '乙偷竊甲所有之名畫，有關甲之損害賠償請求權消滅時效，下列敘述，何者正確？', '["自甲知悉名畫失竊時起，2年間不行使而消滅", "自甲知悉乙偷竊甲之名畫時起，2年間不行使而消滅", "自甲知悉乙偷竊甲之名畫時起，10年間不行使而消滅", "自乙偷竊甲之名畫時起，15年間不行使才消滅 31770 32170"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00228', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲購入屋齡30年之A屋後，因A屋陳舊不堪，而委由乙重新設計裝修。乙完工後，甲入住A屋 時發現，浴室之排水口設置錯誤，無法排水。關於甲乙間之權利義務關係，下列敘述，何者錯誤？', '["甲得定相當期限，請求乙修補，以解決排水問題", "若甲請求乙修補，而乙拒絕修補，甲得請求減少價金", "甲因排水口之瑕疵，而不再信任乙，遂不請求乙修補而自行找第三人修補時，甲得向乙請求償 還修補必要之費用", "甲之瑕疵修補請求權，因瑕疵發見後1年間不行使而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00229', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲、乙、丙三人互約出資購買市區之A房地，以合夥經營商號，並約定由丙執行合夥事務。該商 號嗣後因景氣不佳而負債累累，惟甲、乙個人亦分別積欠丁、戊債務若干尚未償還。下列敘述， 何者錯誤？', '["丁於甲之合夥存續期間內，就甲對於合夥之利益分配請求權，得代位行使之", "戊得聲請扣押乙之股份，乙於扣押實施後兩個月內未向戊清償或提供相當擔保者，自扣押時起 對乙發生退夥之效力", "A房地財產不足清償合夥債務時，甲、乙、丙對於不足之額，連帶負其責任", "執行合夥事務之丙，不須經甲乙兩人之同意，即得任意自行辭任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00230', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '若質權人與出質人未有特別約定時，下列何者非屬動產質權所擔保之債權範圍？', '["遲延利息", "改良質物之費用", "實行質權之費用", "因質物隱有瑕疵而生之損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00231', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲向乙貸款新臺幣（下同）180萬元，以其所有之A屋為乙設定第一次序普通抵押權，甲又向丙 貸款120萬元，以A屋為丙設定第二次序普通抵押權。嗣後，因鄰居丁之過失，致電線走火延燒 而使A屋滅失。下列敘述，何者錯誤？', '["乙對甲之債權，不因A屋滅失而消滅", "乙就甲對丁之賠償債權，有權利質權", "A屋滅失後如留有殘餘物，乙丙對之仍享有抵押權", "乙丙之抵押權均因A屋滅失，隨即消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00232', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列何種財產權不得成為時效取得之客體？', '["普通抵押權", "不動產役權", "區分地上權", "普通地上權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00233', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '以建築物設定普通抵押權時，下列何者非抵押權效力所及之標的物範圍？', '["該建築物對於供役地所設定之通行不動產役權", "該建築物對於其基地所設定之地上權", "該建築物倒塌後所殘餘之鋼筋建材", "該建築物於扣押後所得收取之租金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00234', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於不動產役權之敘述，何者錯誤？', '["不動產役權之全部或一部無存續之必要時，該不動產役權當然消滅，但限於未定期限者", "不動產役權消滅時，不動產役權人應於1個月內取回其所為之設置，否則歸屬於土地所有人", "不動產役權，除於他人之不動產，亦得就自己之不動產設定之；且不限於土地，建築物上亦得 設定之", "需役不動產之地上權人，無須經土地所有人之同意，得自行為該不動產設定不動產役權 31770 32170"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00235', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '不動產共有人間關於共有物之約定，於登記後，對於應有部分之受讓人或取得物權之人具有效力， 不包括下列何種情形？', '["關於共有物之分管約定", "關於共有物之分割約定", "關於共有物禁止分割之約定", "關於共有物禁止處分之約定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
